    33|function compactCurrency(value: number): string {
    34|  if (value >= 1_000_000) {
    35|    const millions = value / 1_000_000;
    36|    return `$${millions % 1 === 0 ? millions.toFixed(0) : millions.toFixed(1)}M`;
    37|  }
    38|  if (value >= 1_000) {
    39|    const thousands = value / 1_000;
    40|    return `$${thousands % 1 === 0 ? thousands.toFixed(0) : thousands.toFixed(1)}K`;
    41|  }
    42|  return `$${Math.round(value)}`;
